// ─── Init Session ──────────────────────────────────────
const msg    = $input.item.json.message;
const userId = String(msg?.from?.id || 'unknown');
const chatId = String(msg?.chat?.id || userId);
const text   = msg?.text || '';
const ts     = new Date().toISOString();
const sessionId = `${userId}_${new Date().toISOString().slice(0,10)}`;

return [{
  json: {
    session_id: sessionId,
    user_id:    userId,
    chat_id:    chatId,
    user_message: text,
    timestamp: ts
  }
}];

const session   = $('Init Session').item.json;
const dbResult  = $input.item.json;
const ctxSummary = dbResult?.context_summary || 'Nouvelle session.';
const recentFacts = dbResult?.recent_facts || [];

const factsText = Array.isArray(recentFacts) && recentFacts.length > 0
  ? recentFacts.map(f => `[${f.type}] ${f.content}`).join('\n')
  : 'Aucun fait mémorisé.';

const enrichedPrompt = `CONTEXTE SESSION:\n${ctxSummary}\n\nFAITS MÉMORISÉS:\n${factsText}\n\nMESSAGE UTILISATEUR:\n${session.user_message}`;

return [{
  json: {
    ...session,
    context_summary: ctxSummary,
    recent_facts: recentFacts,
    enriched_prompt: enrichedPrompt
  }
}];

const agentOutput = $('AI Agent — OpenClaw Brain').item.json.output || '';
const MAX_LEN = 3900;

let formatted = agentOutput;
if (formatted.length > MAX_LEN) {
  formatted = formatted.slice(0, MAX_LEN) + '\n\n_(message tronqué — suite disponible)_';
}

return [{
  json: {
    chat_id: $('Merge Context').item.json.chat_id,
    text: formatted
  }
}];
